import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"my/Safety/cloudflare-api-token.md","filePath":"my/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"my/Safety/cloudflare-api-token.md"};function n(c,e,p,s,u,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials က files ပြောင်းလဲပြီးနောက် Cloudflare CDN cache ကို purge လုပ်နိုင်စေဖို့ ImgBed ကိုခွင့်ပြုပါတယ်။</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>admin panel ကိုဖွင့်ပြီး သွားပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>ဖြည့်ရန်လိုအပ်တာတွေ:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="ဒီ-setting-က-ဘာလုပ်လဲ" tabindex="-1">ဒီ Setting က ဘာလုပ်လဲ <a class="header-anchor" href="#ဒီ-setting-က-ဘာလုပ်လဲ" aria-label="Permalink to &quot;ဒီ Setting က ဘာလုပ်လဲ&quot;">​</a></h2><p>Cloudflare က public image URLs တွေကို cache လုပ်ထားနိုင်ပါတယ်။</p><p>Caching က image delivery ကိုပိုမြန်စေပေမယ့် file ကို delete, block, replace, move လုပ်ပြီးနောက် content အဟောင်းက အချိန်တစ်ခုကြာ ဆက်မြင်နိုင်ပါတယ်။</p><p>Cloudflare API credentials configure ပြီးနောက် ImgBed က အဲဒီ operations တွေပြီးတိုင်း သက်ဆိုင်တဲ့ Cloudflare cache ကို purge လုပ်ဖို့ကြိုးစားပါမယ်။</p><p>ဒီအခြေအနေတွေမှာအသုံးဝင်ပါတယ်:</p><ul><li>image delete လုပ်ပြီး public link ကိုတတ်နိုင်သမျှမြန်မြန်အလုပ်မလုပ်စေချင်လျှင်။</li><li>image block လုပ်ပြီး visitors တွေ original file မမြင်စေချင်လျှင်။</li><li>file ကိုနာမည်တူနဲ့ replace လုပ်ပြီး visitors တွေ version အသစ်ကိုမြန်မြန်မြင်စေချင်လျှင်။</li><li>files ကို move သို့မဟုတ် rename လုပ်ပြီး old path cache ကိုမြန်မြန် refresh စေချင်လျှင်။</li><li>public access rules ပြောင်းပြီး public gallery သို့မဟုတ် random image cache ကိုမြန်မြန် update စေချင်လျှင်။</li></ul><h2 id="ဗလာထားရင်-ဘာဖြစ်မလဲ" tabindex="-1">ဗလာထားရင် ဘာဖြစ်မလဲ <a class="header-anchor" href="#ဗလာထားရင်-ဘာဖြစ်မလဲ" aria-label="Permalink to &quot;ဗလာထားရင် ဘာဖြစ်မလဲ&quot;">​</a></h2><p>ဒီ setting မရှိလည်း ImgBed ကပုံမှန်အလုပ်လုပ်ပါမယ်။</p><p>ကွာခြားချက်က ImgBed က Cloudflare CDN cache ကို actively purge မလုပ်ပါ။ visitors တွေက Cloudflare cache naturally expire ဖြစ်တဲ့အထိ content အဟောင်းကိုဆက်မြင်နိုင်ပါတယ်။</p><h2 id="zone-id-ရှာနည်း" tabindex="-1">Zone ID ရှာနည်း <a class="header-anchor" href="#zone-id-ရှာနည်း" aria-label="Permalink to &quot;Zone ID ရှာနည်း&quot;">​</a></h2><p>Zone ID ဆိုတာ သင့် ImgBed domain သုံးတဲ့ site ရဲ့ Cloudflare Zone ID ဖြစ်ပါတယ်။</p><ol><li>Cloudflare dashboard ထဲ sign in ဝင်ပါ။</li><li>သင့် ImgBed domain ပါတဲ့ site ကိုဖွင့်ပါ။</li><li>site overview page မှာ <code>Zone ID</code> ကိုရှာပါ။</li><li>ImgBed ထဲက <code>Zone ID</code> field ထဲ copy လုပ်ပါ။</li></ol><p>ဒါက site Zone ID ဖြစ်ပြီး account ID မဟုတ်ပါ။</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Cloudflare ထဲ sign in ဝင်တဲ့ email address ထည့်ပါ။</p><p>အောက်မှာထည့်မယ့် API Key နဲ့ကိုက်ညီရပါမယ်။</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Cloudflare Global API Key ကိုထည့်ပါ။</p><ol><li>Cloudflare dashboard ထဲ sign in ဝင်ပါ။</li><li>profile ကိုဖွင့်ပါ။</li><li>API Tokens page ကိုသွားပါ။</li><li><code>Global API Key</code> ကိုရှာပါ။</li><li>view လုပ်ပြီး copy လုပ်ပါ။</li><li>ImgBed ထဲက <code>API Key</code> field ထဲ paste လုပ်ပါ။</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="ဘယ်အချိန်မှာ-effect-ဖြစ်မလဲ" tabindex="-1">ဘယ်အချိန်မှာ Effect ဖြစ်မလဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-effect-ဖြစ်မလဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ Effect ဖြစ်မလဲ&quot;">​</a></h2><p>fields ဖြည့်ပြီးနောက် settings ကို save လုပ်ပါ။</p><p>နောက်ပိုင်း file changes တွေက Cloudflare cache purge လုပ်ဖို့အလိုအလျောက်ကြိုးစားပါမယ်။ setup မလုပ်ခင်ပြီးခဲ့တဲ့ operations တွေကို retroactively purge မလုပ်ပါ။ setup မလုပ်ခင် file delete သို့မဟုတ် replace လုပ်ထားလျှင် Cloudflare cache expire ဖြစ်အောင်စောင့်ပါ သို့မဟုတ် Cloudflare ထဲမှာ manual purge လုပ်ပါ။</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ဒါ-required-လား" tabindex="-1">ဒါ Required လား? <a class="header-anchor" href="#ဒါ-required-လား" aria-label="Permalink to &quot;ဒါ Required လား?&quot;">​</a></h3><p>မဟုတ်ပါ။</p><p>သင့် domain က Cloudflare မသုံးလျှင်၊ သို့မဟုတ် CDN cache delay ကိုစိတ်မပူလျှင် ဗလာထားနိုင်ပါတယ်။</p><h3 id="credentials-မှားရင်-uploads-ပျက်မလား" tabindex="-1">Credentials မှားရင် Uploads ပျက်မလား? <a class="header-anchor" href="#credentials-မှားရင်-uploads-ပျက်မလား" aria-label="Permalink to &quot;Credentials မှားရင် Uploads ပျက်မလား?&quot;">​</a></h3><p>များသောအားဖြင့် မပျက်ပါ။</p><p>credentials မှားတာက ImgBed ကို Cloudflare cache purge မလုပ်နိုင်အောင်ပဲတားပါတယ်။ upload နဲ့ normal file access ကဆက်အလုပ်လုပ်သင့်ပါတယ်။</p><h3 id="deleted-image-က-ဘာကြောင့်-ဆက်ဖွင့်လို့ရနေတာလဲ" tabindex="-1">Deleted Image က ဘာကြောင့် ဆက်ဖွင့်လို့ရနေတာလဲ? <a class="header-anchor" href="#deleted-image-က-ဘာကြောင့်-ဆက်ဖွင့်လို့ရနေတာလဲ" aria-label="Permalink to &quot;Deleted Image က ဘာကြောင့် ဆက်ဖွင့်လို့ရနေတာလဲ?&quot;">​</a></h3><p>အများဆုံးဖြစ်တဲ့အကြောင်းရင်းက Cloudflare က file အဟောင်းကို cache ထားတာပါ။</p><p>Cloudflare API credentials မှန်ကန်လျှင် ImgBed က file delete လုပ်တဲ့အခါ သက်ဆိုင်တဲ့ URL cache ကို purge လုပ်ပါမယ်။</p><h3 id="file-replace-လုပ်ပြီးနောက်-image-အဟောင်းကို-ဘာကြောင့်ဆက်မြင်နေရလဲ" tabindex="-1">File Replace လုပ်ပြီးနောက် Image အဟောင်းကို ဘာကြောင့်ဆက်မြင်နေရလဲ? <a class="header-anchor" href="#file-replace-လုပ်ပြီးနောက်-image-အဟောင်းကို-ဘာကြောင့်ဆက်မြင်နေရလဲ" aria-label="Permalink to &quot;File Replace လုပ်ပြီးနောက် Image အဟောင်းကို ဘာကြောင့်ဆက်မြင်နေရလဲ?&quot;">​</a></h3><p>ဒါလည်း များသောအားဖြင့် CDN cache ကြောင့်ဖြစ်ပါတယ်။</p><p>ဒီ setting configure လုပ်ပြီးနောက် ImgBed က နာမည်တူ file overwrite လုပ်တဲ့အခါ old URL cache ကို purge လုပ်ဖို့ကြိုးစားပါမယ်။</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
